CREATE TABLE IF NOT EXISTS `clanhall` (
  `id` tinyint(3) unsigned NOT NULL DEFAULT '0',
  `ownerId` int(11) NOT NULL DEFAULT '0',
  `paidUntil` bigint(20) NOT NULL DEFAULT '0',
  `auctionEndTime` bigint(20) NOT NULL DEFAULT '0',
  `name` varchar(40) NOT NULL DEFAULT '',
  `last_siege_date` bigint(20) NOT NULL DEFAULT '0',
  `own_date` bigint(20) NOT NULL DEFAULT '0',
  `siege_date` bigint(20) NOT NULL DEFAULT '0',
  `auction_min_bid` bigint(20) NOT NULL DEFAULT '0',
  `auction_length` int(11) NOT NULL DEFAULT '0',
  `auction_desc` text,
  `cycle` int(11) NOT NULL DEFAULT '0',
  `paid_cycle` int(11) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_clanhall_ownerId` (`ownerId`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

